const output = $json.output || '';
const MAX = 3900;
const entries = output.split(/\n\n+/);
const chunks = [];
let current = '';
for (const entry of entries) {
  const candidate = current ? current + '\n\n' + entry : entry;
  if (candidate.length > MAX && current.length > 0) {
    chunks.push(current);
    current = entry;
  } else {
    current = candidate;
  }
}
if (current) chunks.push(current);
return chunks.map((c, idx) => ({ json: { output: c, chunkIndex: idx, chunkTotal: chunks.length } }));
